-- 创建图知识库graph_pattern_tag
CREATE TABLE "public"."knowledge_graph_pattern_tag"
(

    "pattern_tag_id"   int4                                        NOT NULL GENERATED BY DEFAULT AS IDENTITY (
        INCREMENT 1
MINVALUE  1
MAXVALUE 2147483647
START 1
CACHE 1
),
    "space_id"      int4                                        NOT NULL DEFAULT 0,
    "tag_name" varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
    "create_by"     int4                                        NOT NULL DEFAULT 1,
    "update_by"     int4                                        NOT NULL DEFAULT 1,
    "create_time"   timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "update_time"   timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted"       bool                                        NOT NULL DEFAULT false,
    CONSTRAINT "knowledge_graph_pattern_tag_pkey" PRIMARY KEY ("pattern_tag_id")
)
;

ALTER TABLE "public"."knowledge_graph_pattern_tag"
    OWNER TO "postgres";

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_tag"."pattern_tag_id" IS '';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_tag"."space_id" IS '知识库id';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_tag"."create_by" IS '创建人';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_tag"."update_by" IS '更新人';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_tag"."create_time" IS '创建时间';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_tag"."update_time" IS '更新时间';



