-- graph_pattern_edge
CREATE TABLE "public"."knowledge_graph_pattern_edge"
(

    "pattern_edge_id"   int4                                        NOT NULL GENERATED BY DEFAULT AS IDENTITY (
        INCREMENT 1
MINVALUE  1
MAXVALUE 2147483647
START 1
CACHE 1
),
    "space_id"      int4                                        NOT NULL DEFAULT 0,
    "source_value" varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
    "target_value" varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
    "value" varchar(255) COLLATE "pg_catalog"."default" NOT NULL DEFAULT '':: character varying,
    "create_by"     int4                                        NOT NULL DEFAULT 1,
    "update_by"     int4                                        NOT NULL DEFAULT 1,
    "create_time"   timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "update_time"   timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted"       bool                                        NOT NULL DEFAULT false,
    CONSTRAINT "knowledge_graph_pattern_edge_pkey" PRIMARY KEY ("pattern_edge_id")
)
;

ALTER TABLE "public"."knowledge_graph_pattern_edge"
    OWNER TO "postgres";


COMMENT
ON COLUMN "public"."knowledge_graph_pattern_edge"."space_id" IS '知识库id';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_edge"."source_value" IS '起始本体';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_edge"."target_value" IS '目标本体';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_edge"."target_value" IS '目标本体';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_edge"."value" IS '边属性名';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_edge"."create_time" IS '创建时间';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_edge"."update_time" IS '更新时间';

