-- knowledge_graph_pattern_manager
CREATE TABLE "public"."knowledge_graph_pattern_manager"
(

    "manager_id"   int4                                        NOT NULL GENERATED BY DEFAULT AS IDENTITY (
        INCREMENT 1
MINVALUE  1
MAXVALUE 2147483647
START 1
CACHE 1
),
    "space_id"      int4                                        NOT NULL DEFAULT 0,
    "is_flush"      int2                                        NOT NULL DEFAULT 0,
    "create_by"     int4                                        NOT NULL DEFAULT 1,
    "update_by"     int4                                        NOT NULL DEFAULT 1,
    "create_time"   timestamp(0)                                NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "update_time"   timestamp(0)                                NULL DEFAULT NULL,
    "deleted"       bool                                        NOT NULL DEFAULT false,
    CONSTRAINT "knowledge_graph_pattern_manager_pkey" PRIMARY KEY ("manager_id")
)
;

ALTER TABLE "public"."knowledge_graph_pattern_manager"
    OWNER TO "postgres";


COMMENT
ON COLUMN "public"."knowledge_graph_pattern_manager"."space_id" IS '知识库id';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_manager"."is_flush" IS '是否刷新，0表示未刷新，1表示已刷新';


COMMENT
ON COLUMN "public"."knowledge_graph_pattern_manager"."create_time" IS '创建时间';

COMMENT
ON COLUMN "public"."knowledge_graph_pattern_manager"."update_time" IS '更新时间';

