-- 修改 chunk_content 列的数据类型为 text
ALTER TABLE "public"."knowledge_chunk_information"
ALTER COLUMN "chunk_content" TYPE text;

-- 设置 text 类型的默认值为空字符串
ALTER TABLE "public"."knowledge_chunk_information"
ALTER COLUMN "chunk_content" SET DEFAULT '';

