-- 修改 job_id 列：允许 NULL 值并设置默认值为 NULL
ALTER TABLE public.knowledge_chunk_information
ALTER COLUMN job_id DROP NOT NULL,
ALTER COLUMN job_id SET DEFAULT NULL;




